:root {
  /* Blueprint colors (canvas stays light) */
  --color-background: #FAFAF8;
  --color-wall-fill: #2D3748;
  --color-wall-stroke: #1A202C;
  --color-grid-minor: #E4E7EC;
  --color-grid-major: #CDD5DF;
  --color-selection: #10B981;
  --color-selection-fill: rgba(16, 185, 129, 0.08);

  /* UI colors — dark chrome panels */
  --color-text-primary: #E8EAED;
  --color-text-secondary: #9AA0AE;
  --color-text-tertiary: #6B7280;
  --color-panel-bg: #1E2028;
  --color-panel-bg-alt: #252830;
  --color-surface-elevated: #2E3140;
  --color-border: rgba(255, 255, 255, 0.08);
  --color-border-subtle: rgba(255, 255, 255, 0.05);
  --color-accent: #10B981;
  --color-accent-hover: #0EA472;
  --color-accent-subtle: rgba(16, 185, 129, 0.12);
  --color-danger: #F87171;
  --color-danger-hover: #EF4444;
  --color-danger-subtle: rgba(248, 113, 113, 0.10);
  --color-card-bg: #252830;
  --color-card-bg-hover: #2A2E38;
  --color-segment-bg: rgba(255, 255, 255, 0.05);
  --color-segment-active-bg: rgba(255, 255, 255, 0.10);
  --color-segment-active-shadow: 0 1px 3px rgba(0, 0, 0, 0.20), 0 0 0 0.5px rgba(255, 255, 255, 0.06);
  --color-danger-ghost-border: rgba(248, 113, 113, 0.30);
  --color-danger-ghost-bg-hover: rgba(248, 113, 113, 0.10);
  --color-divider: rgba(255, 255, 255, 0.06);
  --color-sticky-bg: rgba(30, 32, 40, 0.92);

  /* Layout */
  --toolbar-height: 56px;
  --sidebar-width: 260px;
  --properties-width: 280px;

  /* Typography */
  --font-ui: 'Outfit', system-ui, -apple-system, sans-serif;
  --font-blueprint: 'JetBrains Mono', 'Courier New', monospace;

  /* Spacing */
  --space-2xs: 2px;
  --space-xs: 4px;
  --space-sm: 8px;
  --space-md: 12px;
  --space-lg: 16px;
  --space-xl: 24px;
  --space-xxl: 32px;

  /* Borders */
  --radius-xs: 4px;
  --radius-sm: 5px;
  --radius-md: 8px;
  --radius-lg: 12px;

  /* Shadows */
  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.12);
  --shadow-md: 0 2px 8px rgba(0, 0, 0, 0.18);
  --shadow-lg: 0 4px 16px rgba(0, 0, 0, 0.24);
  --shadow-overlay: 0 8px 32px rgba(0, 0, 0, 0.32), 0 0 0 1px rgba(255, 255, 255, 0.06);

  /* Transitions */
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --duration-fast: 0.1s;
  --duration-normal: 0.2s;
  --duration-smooth: 0.3s;
}

