.walkOverlay {
  position: absolute;
  left: 16px;
  top: 16px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  max-width: min(320px, calc(100% - 32px));
  padding: 12px 14px;
  border: 1px solid rgba(45, 78, 109, 0.18);
  border-radius: var(--radius-md);
  background: linear-gradient(180deg, rgba(246, 249, 252, 0.95), rgba(236, 242, 247, 0.9));
  box-shadow: 0 12px 28px rgba(37, 48, 61, 0.12);
  pointer-events: none;
}

.walkOverlayTitle {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #35536f;
}

.walkOverlayBody {
  font-size: 12px;
  line-height: 1.5;
  color: #1A1D23;
}

.inspectCard {
  position: absolute;
  top: 16px;
  right: 16px;
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 220px;
  max-width: min(280px, calc(100% - 32px));
