  1→import { lazy, Suspense, useState, useEffect, useCallback, useMemo, useRef } from 'react';
  2→import { ProjectProvider, useProject } from './ProjectProvider';
  3→import { EditorProvider, useEditor } from './EditorProvider';
  4→import { ClipboardProvider } from './ClipboardProvider';
  5→import SvgCanvas from '@/renderers/SvgCanvas';
  6→import SheetCanvas from '@/renderers/SheetCanvas';
  7→import Toolbar from '@/ui/Toolbar';
  8→import Sidebar from '@/ui/Sidebar';
  9→import PropertiesPanel from '@/ui/PropertiesPanel';
 10→import Modal from '@/ui/Modal';
 11→import { createProject } from '@/domain/models';
 12→import { getDefaultActiveFloorId, getOrderedFloors } from '@/domain/floorModels';
 13→import { saveProject, loadProject, listProjects, deleteProject } from '@/persistence/storage';
 14→import {
 15→  exportProjectFile,
 16→  importProjectFile,
 17→  isFilePickerAbortError,
 18→  openProjectFile,
 19→} from '@/persistence/fileTransfer';
 20→import { useAutosave } from '@/persistence/useAutosave';
 21→import { isTypingTarget } from '@/utils/keyboard';
 22→import styles from './App.module.css';
 23→import modalStyles from '@/ui/Modal.module.css';
 24→
 25→const ThreePreviewPanel = lazy(() => import('@/three/viewer/ThreePreviewPanel'));
 26→
 27→function EditorShell({
 28→  project,
 29→  handleNew,
 30→  handleSave,
 31→  handleLoadClick,
 32→  isSidebarCollapsed,
 33→  isPropertiesCollapsed,
 34→  onToggleSidebar,
 35→  onToggleProperties,
 36→}) {
 37→  const {
 38→    workspaceMode,
 39→    activeSheetId,
 40→    activeFloorId,
 41→    maximizedPanel,
 42→    dispatch: editorDispatch,
 43→  } = useEditor();
 44→
 45→  useEffect(() => {
 46→    const sheets = project.sheets || [];
 47→    if (!sheets.length) {
 48→      if (activeSheetId !== null) {
 49→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
 50→      }
 51→      if (workspaceMode === 'sheet') {
 52→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 53→      }
 54→      return;
 55→    }
 56→
 57→    if (!activeSheetId || !sheets.some((sheet) => sheet.id === activeSheetId)) {
 58→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheets[0].id });
 59→    }
 60→  }, [activeSheetId, editorDispatch, project.sheets, workspaceMode]);
 61→
 62→  return (
 63→    <div
 64→      className={styles.layout}
 65→      style={{
 66→        '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
 67→        '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
 68→      }}
 69→    >
 70→      <div className={styles.toolbar}>
 71→        <Toolbar
 72→          onNew={handleNew}
 73→          onSave={handleSave}
 74→          onLoad={handleLoadClick}
 75→          isSidebarCollapsed={isSidebarCollapsed}
 76→          isPropertiesCollapsed={isPropertiesCollapsed}
 77→          onToggleSidebar={onToggleSidebar}
 78→          onToggleProperties={onToggleProperties}
 79→        />
 80→      </div>
 81→      <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : ''}`}>
 82→        <Sidebar />
 83→      </div>
 84→      <div className={styles.canvas}>
 85→        {workspaceMode === 'sheet' ? (
 86→          <SheetCanvas />
 87→        ) : (
 88→          <div className={`${styles.modelWorkspace} ${maximizedPanel ? styles.workspaceMaximized : ''}`}>
 89→            {maximizedPanel !== 'preview' && (
 90→              <div className={styles.primaryCanvas}>
 91→                <SvgCanvas />
 92→              </div>
 93→            )}
 94→            {maximizedPanel !== 'canvas' && (
 95→              <div className={styles.preview}>
 96→                <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
 97→                  <ThreePreviewPanel
 98→                    project={project}
 99→                    activeFloorId={activeFloorId}
100→                    isMaximized={maximizedPanel === 'preview'}
101→                    onToggleMaximize={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'preview' })}
102→                  />
103→                </Suspense>
104→              </div>
105→            )}
106→          </div>
107→        )}
108→      </div>
109→      <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : ''}`}>
110→        <PropertiesPanel />
111→      </div>
112→    </div>
