202→            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
203→            title={`${label} View`}
204→          >
205→            {label}
206→          </button>
207→        ))}
208→        <button
209→          className={activeViewKey === 'sheets' ? styles.segmentedBtnActive : styles.segmentedBtn}
210→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
211→          title="Sheet Workspace"
212→        >
213→          Sheets
214→        </button>
215→      </div>
216→
217→      {/* Tool palette - inline row of 12 icons */}
218→      <div className={styles.toolPalette}>
219→        <span className={styles.groupLabel}>Tools</span>
220→        {toolItems.map(({ tool, label, shortcut, Icon }) => (
221→          <button
222→            key={tool}
223→            className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
224→            onClick={() => setTool(tool)}
225→            disabled={!isPlanView}
226→            title={`${label} (${shortcut})`}
227→            aria-label={label}
228→          >
229→            <Icon className={styles.toolPaletteIcon} />
230→          </button>
231→        ))}
232→      </div>
233→
234→      {/* Fixtures palette */}
235→      <div className={styles.fixturePalette}>
236→        <span className={styles.fixturePaletteLabel}>Fixtures</span>
237→        {fixtureItems.map(({ fixtureType, label, Icon }) => {
238→          const isActive = activeTool === TOOLS.FIXTURE && toolState.fixtureType === fixtureType;
239→          return (
240→            <button
241→              key={fixtureType}
242→              className={isActive ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
243→              onClick={() => {
244→                editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
245→                editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType, previewRotation: 0 } });
246→              }}
247→              disabled={!isPlanView}
248→              title={`${label} (F)`}
249→              aria-label={label}
250→            >
251→              <Icon className={styles.toolPaletteIcon} />
252→            </button>
253→          );
254→        })}
255→      </div>
256→
257→      {/* Panel toggles & utility toggles */}
258→      <div className={styles.group}>
259→        <span className={styles.groupLabel}>Panels</span>
260→        <button
261→          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''}`}
262→          onClick={onToggleSidebar}
263→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
264→          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
265→        >
266→          <SidebarIcon className={styles.icon} />
267→        </button>
268→        <button
269→          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''}`}
270→          onClick={onToggleProperties}
271→          title={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
272→          aria-label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
273→        >
274→          <PropertiesIcon className={styles.icon} />
275→        </button>
276→        <div className={styles.divider} />
277→        <span className={styles.groupLabel}>Display</span>
278→        <button
279→          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
280→          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
281→          title="Toggle Grid"
282→          aria-label="Toggle Grid"
283→        >
284→          <GridIcon className={styles.icon} />
285→        </button>
286→        <button
287→          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
288→          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
289→          title="Toggle Snap"
290→          aria-label="Toggle Snap"
291→        >
292→          <SnapIcon className={styles.icon} />
293→        </button>
294→        <button
295→          className={styles.btn}
296→          onClick={handleDetectRooms}
297→          title="Auto-detect Rooms"
298→          disabled={!isPlanView}
299→          aria-label="Auto-detect Rooms"
300→        >
301→          <DetectRoomsIcon className={styles.icon} />
302→        </button>
303→      </div>
304→
305→      <div className={styles.spacer} />
306→    </div>
307→  );
308→}
